#include <iostream>

int finalPrice(int price, int discountPercent)
{
    return price - (price * discountPercent / 100);
}

int main()
{
    int p {};
    int d {};
    std::cin >> p >> d;
    std::cout << "Final: " << finalPrice(p, d) << '\n';
    return 0;
}
